const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = input[idx++];
let outputs = [];
for (let tc = 0; tc < T; tc++) {
  const N = input[idx++];
  let arr = input.slice(idx, idx + N);
  idx += N;
  arr.sort((a, b) => a - b);
  const mid = Math.floor((N + 1) / 2);
  let ans = [];
  for (let i = 0; i < mid && i + mid < N; i++) {
    ans.push(arr[i]);
    ans.push(arr[i + mid]);
  }
  if (N % 2 === 1 && ans.length < N) ans.push(arr[mid - 1]);
  outputs.push(ans.join(' '));
}
console.log(outputs.join('\n'));

